#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    string s;
    cin >> s;
    unordered_map<char, int> freq;
    for(char c : s){
        freq[c]++;
    }
    vector<pair<char, int>> sorted_chars(freq.begin(), freq.end());
    sort(sorted_chars.begin(), sorted_chars.end(), [](const auto& a, const auto& b){
        if(a.second == b.second) return a.first < b.first;
        return a.second > b.second;
    });
    string sorted_string;
    for(auto& p : sorted_chars){
        sorted_string += string(p.second, p.first);
    }
    cout << sorted_string << endl;
    return 0;
}
